import { useState } from 'react';
import { Filter, X, ChevronDown, ChevronUp } from 'lucide-react';
import { Button } from './ui/button';

export interface FilterOptions {
    categories: string[];
    platforms: string[];
    priceRange: [number, number];
    availability: string[];
    deals: string[];
    brands: string[];
}

interface FilterSidebarProps {
    filters: FilterOptions;
    onFilterChange: (filters: FilterOptions) => void;
    onClose?: () => void;
    isMobile?: boolean;
}

export default function FilterSidebar({ filters, onFilterChange, onClose, isMobile = false }: FilterSidebarProps) {
    const [expandedSections, setExpandedSections] = useState<{ [key: string]: boolean }>({
        category: true,
        platform: true,
        price: true,
        availability: true,
        deals: true,
        brand: true,
    });

    const toggleSection = (section: string) => {
        setExpandedSections(prev => ({ ...prev, [section]: !prev[section] }));
    };

    const categories = ['All Products', 'Controllers', 'Headsets', 'Keyboards', 'Mice', 'Consoles', 'Monitors', 'Chairs', 'Audio', 'Accessories'];
    const platforms = ['PS5', 'PS4', 'PC', 'Xbox', 'Nintendo Switch'];
    const availabilityOptions = ['In Stock', 'Pre-order'];
    const dealOptions = ['Sale', 'Bundle', 'Best Value'];
    const brands = ['Sony', 'Microsoft', 'Razer', 'Logitech', 'SteelSeries', 'Corsair', 'HyperX'];

    const priceRanges = [
        { label: 'Under KSh 5,000', value: [0, 5000] as [number, number] },
        { label: 'KSh 5,000 - 15,000', value: [5000, 15000] as [number, number] },
        { label: 'KSh 15,000 - 30,000', value: [15000, 30000] as [number, number] },
        { label: 'KSh 30,000 - 50,000', value: [30000, 50000] as [number, number] },
        { label: 'Above KSh 50,000', value: [50000, 999999] as [number, number] },
    ];

    const handleCategoryToggle = (category: string) => {
        const newCategories = filters.categories.includes(category)
            ? filters.categories.filter(c => c !== category)
            : [...filters.categories, category];
        onFilterChange({ ...filters, categories: newCategories });
    };

    const handlePlatformToggle = (platform: string) => {
        const newPlatforms = filters.platforms.includes(platform)
            ? filters.platforms.filter(p => p !== platform)
            : [...filters.platforms, platform];
        onFilterChange({ ...filters, platforms: newPlatforms });
    };

    const handleAvailabilityToggle = (option: string) => {
        const newAvailability = filters.availability.includes(option)
            ? filters.availability.filter(a => a !== option)
            : [...filters.availability, option];
        onFilterChange({ ...filters, availability: newAvailability });
    };

    const handleDealToggle = (deal: string) => {
        const newDeals = filters.deals.includes(deal)
            ? filters.deals.filter(d => d !== deal)
            : [...filters.deals, deal];
        onFilterChange({ ...filters, deals: newDeals });
    };

    const handleBrandToggle = (brand: string) => {
        const newBrands = filters.brands.includes(brand)
            ? filters.brands.filter(b => b !== brand)
            : [...filters.brands, brand];
        onFilterChange({ ...filters, brands: newBrands });
    };

    const handlePriceRangeSelect = (range: [number, number]) => {
        onFilterChange({ ...filters, priceRange: range });
    };

    const clearAllFilters = () => {
        onFilterChange({
            categories: [],
            platforms: [],
            priceRange: [0, 999999],
            availability: [],
            deals: [],
            brands: [],
        });
    };

    const activeFilterCount =
        filters.categories.length +
        filters.platforms.length +
        filters.availability.length +
        filters.deals.length +
        filters.brands.length +
        (filters.priceRange[0] !== 0 || filters.priceRange[1] !== 999999 ? 1 : 0);

    const FilterSection = ({ title, section, children }: { title: string; section: string; children: React.ReactNode }) => (
        <div className="border-b border-zinc-800 pb-4">
            <button
                onClick={() => toggleSection(section)}
                className="flex items-center justify-between w-full mb-3 group"
            >
                <span className="text-sm font-black uppercase tracking-wider text-white group-hover:text-red-500 transition-colors">
                    {title}
                </span>
                {expandedSections[section] ? (
                    <ChevronUp className="h-4 w-4 text-zinc-500 group-hover:text-red-500 transition-colors" />
                ) : (
                    <ChevronDown className="h-4 w-4 text-zinc-500 group-hover:text-red-500 transition-colors" />
                )}
            </button>
            {expandedSections[section] && <div className="space-y-2">{children}</div>}
        </div>
    );

    const CheckboxOption = ({ label, checked, onChange }: { label: string; checked: boolean; onChange: () => void }) => (
        <label className="flex items-center gap-3 cursor-pointer group">
            <div className={`w-4 h-4 border-2 flex items-center justify-center transition-all ${checked ? 'bg-red-600 border-red-600' : 'border-zinc-700 group-hover:border-red-600'
                }`}>
                {checked && <div className="w-2 h-2 bg-white" />}
            </div>
            <span className={`text-xs font-bold uppercase tracking-wide transition-colors ${checked ? 'text-white' : 'text-zinc-500 group-hover:text-zinc-300'
                }`}>
                {label}
            </span>
        </label>
    );

    return (
        <div className={`${isMobile ? 'fixed inset-0 z-50 bg-black' : 'sticky top-24 h-[calc(100vh-8rem)]'} overflow-y-auto scrollbar-hide`}>
            {/* Header */}
            <div className="flex items-center justify-between p-4 border-b border-zinc-800 bg-zinc-950">
                <div className="flex items-center gap-3">
                    <Filter className="h-5 w-5 text-red-600" />
                    <h2 className="text-lg font-black uppercase tracking-wider text-white">
                        Filters
                    </h2>
                    {activeFilterCount > 0 && (
                        <span className="bg-red-600 text-white text-xs font-black px-2 py-0.5 rounded-full">
                            {activeFilterCount}
                        </span>
                    )}
                </div>
                {isMobile && onClose && (
                    <button onClick={onClose} className="p-2 hover:bg-zinc-800 text-zinc-500 hover:text-red-600 transition-colors">
                        <X className="h-5 w-5" />
                    </button>
                )}
            </div>

            {/* Clear All */}
            {activeFilterCount > 0 && (
                <div className="p-4 border-b border-zinc-800">
                    <Button
                        onClick={clearAllFilters}
                        className="w-full bg-transparent border border-zinc-800 text-zinc-500 hover:bg-red-600 hover:text-white hover:border-red-600 transition-all duration-300 rounded-none text-xs font-black uppercase tracking-widest"
                    >
                        Clear All Filters
                    </Button>
                </div>
            )}

            {/* Filter Sections */}
            <div className="p-4 space-y-6">
                {/* Category */}
                <FilterSection title="Category" section="category">
                    {categories.map(category => (
                        <CheckboxOption
                            key={category}
                            label={category}
                            checked={filters.categories.includes(category)}
                            onChange={() => handleCategoryToggle(category)}
                        />
                    ))}
                </FilterSection>

                {/* Platform */}
                <FilterSection title="Platform" section="platform">
                    {platforms.map(platform => (
                        <CheckboxOption
                            key={platform}
                            label={platform}
                            checked={filters.platforms.includes(platform)}
                            onChange={() => handlePlatformToggle(platform)}
                        />
                    ))}
                </FilterSection>

                {/* Price Range */}
                <FilterSection title="Price Range" section="price">
                    {priceRanges.map((range, index) => (
                        <label key={index} className="flex items-center gap-3 cursor-pointer group">
                            <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center transition-all ${filters.priceRange[0] === range.value[0] && filters.priceRange[1] === range.value[1]
                                ? 'border-red-600'
                                : 'border-zinc-700 group-hover:border-red-600'
                                }`}>
                                {filters.priceRange[0] === range.value[0] && filters.priceRange[1] === range.value[1] && (
                                    <div className="w-2 h-2 rounded-full bg-red-600" />
                                )}
                            </div>
                            <span
                                onClick={() => handlePriceRangeSelect(range.value)}
                                className={`text-xs font-bold uppercase tracking-wide transition-colors ${filters.priceRange[0] === range.value[0] && filters.priceRange[1] === range.value[1]
                                    ? 'text-white'
                                    : 'text-zinc-500 group-hover:text-zinc-300'
                                    }`}
                            >
                                {range.label}
                            </span>
                        </label>
                    ))}
                </FilterSection>

                {/* Availability */}
                <FilterSection title="Availability" section="availability">
                    {availabilityOptions.map(option => (
                        <CheckboxOption
                            key={option}
                            label={option}
                            checked={filters.availability.includes(option)}
                            onChange={() => handleAvailabilityToggle(option)}
                        />
                    ))}
                </FilterSection>

                {/* Deals */}
                <FilterSection title="Deals" section="deals">
                    {dealOptions.map(deal => (
                        <CheckboxOption
                            key={deal}
                            label={deal}
                            checked={filters.deals.includes(deal)}
                            onChange={() => handleDealToggle(deal)}
                        />
                    ))}
                </FilterSection>

                {/* Brand */}
                <FilterSection title="Brand" section="brand">
                    {brands.map(brand => (
                        <CheckboxOption
                            key={brand}
                            label={brand}
                            checked={filters.brands.includes(brand)}
                            onChange={() => handleBrandToggle(brand)}
                        />
                    ))}
                </FilterSection>
            </div>
        </div>
    );
}

import { Zap, Tag, TrendingUp } from 'lucide-react';

interface QuickFilterPill {
    label: string;
    icon?: React.ComponentType<{ className?: string }>;
    filter: {
        type: 'price' | 'category' | 'platform' | 'deal';
        value: any;
    };
}

interface QuickFilterPillsProps {
    onFilterSelect: (filter: QuickFilterPill['filter']) => void;
}

export default function QuickFilterPills({ onFilterSelect }: QuickFilterPillsProps) {
    const quickFilters: QuickFilterPill[] = [
        {
            label: 'Under KSh 5,000',
            icon: Tag,
            filter: { type: 'price', value: [0, 5000] }
        },
        {
            label: 'PS5 Controllers',
            icon: Zap,
            filter: { type: 'category', value: 'Controllers' }
        },
        {
            label: 'Headsets',
            icon: Zap,
            filter: { type: 'category', value: 'Headsets' }
        },
        {
            label: 'On Sale',
            icon: TrendingUp,
            filter: { type: 'deal', value: 'Sale' }
        },
        {
            label: 'PC Gaming',
            icon: Zap,
            filter: { type: 'platform', value: 'PC' }
        },
        {
            label: 'Best Value',
            icon: TrendingUp,
            filter: { type: 'deal', value: 'Best Value' }
        },
    ];

    return (
        <div className="mb-6">
            <div className="flex items-center gap-3 mb-3">
                <Zap className="h-4 w-4 text-red-600" />
                <h3 className="text-xs font-black uppercase tracking-wider text-zinc-400">
                    Quick Filters
                </h3>
            </div>
            <div className="flex flex-wrap gap-2">
                {quickFilters.map((filter, index) => {
                    const Icon = filter.icon;
                    return (
                        <button
                            key={index}
                            onClick={() => onFilterSelect(filter.filter)}
                            className="group relative bg-zinc-900/50 border border-zinc-800 hover:border-red-600 px-4 py-2 transition-all duration-300 hover:-translate-y-0.5"
                            style={{ clipPath: 'polygon(0 0, 95% 0, 100% 25%, 100% 100%, 5% 100%, 0 75%)' }}
                        >
                            <div className="flex items-center gap-2">
                                {Icon && <Icon className="h-3.5 w-3.5 text-zinc-500 group-hover:text-red-500 transition-colors" />}
                                <span className="text-xs font-black uppercase tracking-wide text-zinc-400 group-hover:text-white transition-colors">
                                    {filter.label}
                                </span>
                            </div>
                            {/* Glow effect on hover */}
                            <div className="absolute -inset-1 bg-red-600/10 blur-lg opacity-0 group-hover:opacity-100 transition-opacity -z-10" />
                        </button>
                    );
                })}
            </div>
        </div>
    );
}

import { useState } from 'react';
import { Package, Search, MapPin, Clock, CheckCircle, Target, ChevronRight } from 'lucide-react';
import { Sheet, SheetContent, SheetHeader, SheetTitle } from './ui/sheet';
import { Button } from './ui/button';

interface TrackOrderProps {
  isOpen: boolean;
  onClose: () => void;
}

export default function TrackOrder({ isOpen, onClose }: TrackOrderProps) {
  const [orderNumber, setOrderNumber] = useState('');
  const [trackingData, setTrackingData] = useState<any>(null);

  const handleTrack = () => {
    // Mock tracking data
    setTrackingData({
      orderNumber: orderNumber || 'ORD-2024-001',
      status: 'IN TRANSIT',
      estimatedDelivery: '2024-01-15',
      timeline: [
        { status: 'MANIFEST CREATED', date: '2024-01-10', completed: true },
        { status: 'PROCESSING AT HQ', date: '2024-01-11', completed: true },
        { status: 'DEPARTED FACILITY', date: '2024-01-12', completed: true },
        { status: 'IN TRANSIT', date: '2024-01-13', completed: true },
        { status: 'DELIVERED TO SECTOR', date: '2024-01-15', completed: false }
      ]
    });
  };

  return (
    <Sheet open={isOpen} onOpenChange={onClose}>
      <SheetContent className="bg-zinc-950 border-l border-zinc-800 text-white">
        <SheetHeader className="border-b border-zinc-900 pb-4 sm:pb-6">
          <SheetTitle className="flex items-center gap-3 text-white font-black italic uppercase tracking-tighter text-xl sm:text-2xl">
            <Target className="h-5 w-5 sm:h-6 sm:w-6 text-red-600" />
            TRACK <span className="text-red-600">OPS</span>
          </SheetTitle>
          <p className="text-[8px] sm:text-[10px] font-black text-zinc-500 uppercase tracking-widest">Monitor asset deployment in real-time</p>
        </SheetHeader>

        <div className="mt-10 space-y-10">
          <div className="space-y-3">
            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">MANIFEST NUMBER</label>
            <div className="flex gap-2">
              <input
                type="text"
                value={orderNumber}
                onChange={(e) => setOrderNumber(e.target.value)}
                placeholder="ENTER ORDER ID"
                className="flex-1 bg-zinc-900 border border-zinc-800 px-4 py-3 text-white placeholder:text-zinc-700 rounded-none focus:outline-none focus:border-red-600 font-black uppercase text-xs"
              />
              <Button onClick={handleTrack} className="bg-red-600 hover:bg-red-700 rounded-none px-6">
                <Search className="h-4 w-4" />
              </Button>
            </div>
          </div>

          {trackingData && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
              <div className="bg-red-600/5 border border-red-600/20 p-6 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <Package className="h-12 w-12 text-red-600" />
                </div>
                <div className="space-y-3 relative z-10">
                  <div className="flex items-center gap-3">
                    <div className="h-2 w-2 rounded-full bg-red-600 animate-pulse" />
                    <span className="text-xs font-black uppercase tracking-widest text-white">STATUS: {trackingData.status}</span>
                  </div>
                  <div className="flex items-center gap-3 text-[10px] font-black text-zinc-500 uppercase tracking-widest">
                    <Clock className="h-3 w-3" />
                    <span>ESTIMATED ARRIVAL: {trackingData.estimatedDelivery}</span>
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                <h3 className="text-[10px] font-black text-white uppercase tracking-widest border-l-2 border-red-600 pl-3">DEPLOYMENT TIMELINE</h3>
                <div className="space-y-6 relative before:absolute before:left-3 before:top-2 before:bottom-2 before:w-px before:bg-zinc-800">
                  {trackingData.timeline.map((item: any, index: number) => (
                    <div key={index} className="flex items-start gap-6 relative">
                      <div className={`w-6 h-6 rounded-none flex items-center justify-center z-10 rotate-45 border ${item.completed ? 'bg-red-600 border-red-600' : 'bg-zinc-900 border-zinc-800'
                        }`}>
                        {item.completed && <CheckCircle className="h-3 w-3 text-white -rotate-45" />}
                      </div>
                      <div className="flex-1 pt-0.5">
                        <p className={`text-xs font-black uppercase tracking-widest ${item.completed ? 'text-white' : 'text-zinc-600'}`}>
                          {item.status}
                        </p>
                        <p className="text-[10px] font-bold text-zinc-500 mt-1">{item.date}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </SheetContent>
    </Sheet>
  );
}

import { useState, useEffect } from 'react';
import { Save, Globe, CreditCard, Mail, BarChart3, Upload, Share2 } from 'lucide-react';
import { supabase } from '../../lib/supabase';

interface SettingsData {
  general: {
    siteName: string;
    siteDescription: string;
    contactEmail: string;
    currency: string;
  };
  payments: {
    stripeEnabled: boolean;
    paypalEnabled: boolean;
  };
  features: {
    analyticsEnabled: boolean;
    chatSupportEnabled: boolean;
    reviewsEnabled: boolean;
    wishlistEnabled: boolean;
  };
  social: {
    facebook: string;
    twitter: string;
    instagram: string;
  };
}

export default function Settings() {
  const [settings, setSettings] = useState<SettingsData>({
    general: {
      siteName: 'THE KRYPT',
      siteDescription: 'Elite gaming electronics and cutting-edge battle gear.',
      contactEmail: 'contact@thekrypt.com',
      currency: 'KSh'
    },
    payments: {
      stripeEnabled: true,
      paypalEnabled: false
    },
    features: {
      analyticsEnabled: true,
      chatSupportEnabled: true,
      reviewsEnabled: true,
      wishlistEnabled: true
    },
    social: {
      facebook: '',
      twitter: '',
      instagram: ''
    }
  });

  const [activeSection, setActiveSection] = useState('general');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    try {
      const { data, error } = await supabase
        .from('settings')
        .select('key, value');

      if (error) throw error;

      if (data && data.length > 0) {
        const settingsObj = data.reduce((acc, item) => {
          acc[item.key as keyof SettingsData] = item.value;
          return acc;
        }, {} as Partial<SettingsData>);

        setSettings(prev => ({ ...prev, ...settingsObj }));
      }
    } catch (error) {
      console.error('Error loading settings:', error);
    }
  };

  const handleSave = async () => {
    setLoading(true);
    try {
      // Save each section as a separate row with JSONB value
      for (const [section, sectionData] of Object.entries(settings)) {
        const { error } = await supabase
          .from('settings')
          .upsert({
            key: section,
            value: sectionData,
            updated_at: new Date().toISOString()
          }, { onConflict: 'key' });

        if (error) throw error;
      }

      alert('Settings saved successfully!');
    } catch (error) {
      console.error('Error saving settings:', error);
      alert('Error saving settings. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const updateSetting = (section: keyof SettingsData, key: string, value: any) => {
    setSettings(prev => ({
      ...prev,
      [section]: {
        ...prev[section],
        [key]: value
      }
    }));
  };

  const sections = [
    { id: 'general', label: 'General', icon: Globe },
    { id: 'payments', label: 'Payments', icon: CreditCard },
    { id: 'features', label: 'Features', icon: BarChart3 },
    { id: 'social', label: 'Social Media', icon: Share2 }
  ];

  return (
    <div className="max-w-6xl mx-auto p-6">
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-black uppercase tracking-tighter text-white">COMMAND CENTER <span className="text-red-600">SETTINGS</span></h1>
        <button
          onClick={handleSave}
          disabled={loading}
          className="flex items-center gap-2 bg-red-600 text-white px-4 py-2 rounded-none hover:bg-red-700 disabled:opacity-50 font-black uppercase tracking-widest text-xs"
        >
          <Save className="w-4 h-4" />
          {loading ? 'Saving...' : 'Save Changes'}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Sidebar */}
        <div className="lg:col-span-1">
          <nav className="space-y-2">
            {sections.map(section => {
              const Icon = section.icon;
              return (
                <button
                  key={section.id}
                  onClick={() => setActiveSection(section.id)}
                  className={`w-full flex items-center gap-3 px-3 py-2 rounded-none text-left transition-colors ${activeSection === section.id
                      ? 'bg-red-600/10 text-red-600 border border-red-600/20'
                      : 'text-zinc-400 hover:bg-zinc-900'
                    }`}
                >
                  <Icon className="w-4 h-4" />
                  {section.label}
                </button>
              );
            })}
          </nav>
        </div>

        {/* Content */}
        <div className="lg:col-span-3">
          <div className="bg-zinc-900 border border-zinc-800 rounded-none p-6 text-white">
            {activeSection === 'general' && (
              <div className="space-y-6">
                <h2 className="text-lg font-semibold">General Settings</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Site Name
                    </label>
                    <input
                      type="text"
                      value={settings.general.siteName}
                      onChange={(e) => updateSetting('general', 'siteName', e.target.value)}
                      className="w-full px-3 py-2 bg-zinc-900 border border-zinc-800 text-white rounded-none focus:ring-2 focus:ring-red-600 focus:border-transparent uppercase font-bold text-xs"
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Contact Email
                    </label>
                    <input
                      type="email"
                      value={settings.general.contactEmail}
                      onChange={(e) => updateSetting('general', 'contactEmail', e.target.value)}
                      className="w-full px-3 py-2 bg-zinc-900 border border-zinc-800 text-white rounded-none focus:ring-2 focus:ring-red-600 focus:border-transparent font-bold text-xs"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Site Description
                  </label>
                  <textarea
                    value={settings.general.siteDescription}
                    onChange={(e) => updateSetting('general', 'siteDescription', e.target.value)}
                    rows={3}
                    className="w-full px-3 py-2 bg-zinc-900 border border-zinc-800 text-white rounded-none focus:ring-2 focus:ring-red-600 focus:border-transparent font-bold text-xs"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Currency
                  </label>
                  <select
                    value={settings.general.currency}
                    onChange={(e) => updateSetting('general', 'currency', e.target.value)}
                    className="w-full px-3 py-2 bg-zinc-900 border border-zinc-800 text-white rounded-none focus:ring-2 focus:ring-red-600 focus:border-transparent font-bold text-xs"
                  >
                    <option value="KSh">KSh - Kenyan Shilling</option>
                    <option value="USD">USD - US Dollar</option>
                    <option value="EUR">EUR - Euro</option>
                  </select>
                </div>
              </div>
            )}

            {activeSection === 'payments' && (
              <div className="space-y-6">
                <h2 className="text-lg font-semibold">Payment Settings</h2>

                <div className="space-y-4">
                  <div className="flex items-center justify-between p-4 border rounded-lg">
                    <div>
                      <h3 className="font-medium">Stripe</h3>
                      <p className="text-sm text-gray-600">Accept credit card payments</p>
                    </div>
                    <label className="relative inline-flex items-center cursor-pointer">
                      <input
                        type="checkbox"
                        checked={settings.payments.stripeEnabled}
