                                        <motion.button
                                            key={exp.id}
                                            whileHover={{ scale: 1.02, y: -4 }}
                                            whileTap={{ scale: 0.98 }}
                                            onClick={() => handleExperienceSelect(exp.id)}
                                            className="relative bg-gradient-to-b from-zinc-900 to-zinc-950 border-2 border-zinc-800 hover:border-red-600 p-8 text-left transition-all duration-300 group"
                                            style={{ clipPath: 'polygon(0 0, 100% 0, 100% calc(100% - 24px), calc(100% - 24px) 100%, 0 100%)' }}
                                        >
                                            <div className="absolute top-4 right-4 flex items-center gap-2 bg-green-600/20 px-3 py-1 rounded-full border border-green-600/40">
                                                <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
                                                <span className="text-[8px] font-black text-green-500 uppercase tracking-widest">{exp.available} Available</span>
                                            </div>

                                            <div className="mb-6">
                                                <div className="w-16 h-16 bg-red-600/10 border-2 border-red-600/30 rounded-lg flex items-center justify-center mb-4 group-hover:bg-red-600 group-hover:border-red-600 transition-all">
                                                    <Icon className="w-8 h-8 text-red-600 group-hover:text-white transition-colors" />
                                                </div>
                                                <h3 className="text-2xl font-black uppercase tracking-tight text-white mb-2">{exp.name}</h3>
                                                <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Minimum {exp.minTime} minutes</p>
                                            </div>

                                            <div className="space-y-2">
                                                <div className="flex items-center justify-between text-sm">
                                                    <span className="text-zinc-500 font-bold uppercase tracking-wide">Starting from</span>
                                                    <span className="text-2xl font-black text-red-600">KSh {exp.packages[0].price}</span>
                                                </div>
                                            </div>

                                            <div className="mt-6 flex items-center gap-2 text-red-600 font-black text-xs uppercase tracking-wider">
                                                SELECT <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                                            </div>
                                        </motion.button>
                                    );
                                })}
                            </div>

                            {/* Passes Section */}
                            <div className="mt-24 pt-16 border-t border-zinc-900">
                                <div className="text-center mb-12">
                                    <div className="inline-flex items-center gap-3 mb-4">
                                        <Star className="w-5 h-5 text-amber-500" />
                                        <h3 className="text-3xl font-black italic tracking-tighter text-white uppercase">
                                            Save with <span className="text-amber-500">Passes</span>
                                        </h3>
                                        <Star className="w-5 h-5 text-amber-500" />
                                    </div>
                                    <p className="text-zinc-500 text-sm font-bold uppercase tracking-widest">
                                        Prepaid packages for consistent gaming
                                    </p>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                    {passes.map((pass) => (
                                        <div
                                            key={pass.id}
                                            className="relative bg-zinc-900/50 border-2 border-zinc-800 p-6 hover:border-amber-500/50 transition-all group"
                                        >
                                            {pass.badge && (
                                                <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-amber-500 px-4 py-1 text-[8px] font-black text-black uppercase tracking-widest">
                                                    {pass.badge}
                                                </div>
                                            )}
                                            <h4 className="text-xl font-black uppercase tracking-tight text-white mb-2">{pass.name}</h4>
                                            <p className="text-zinc-500 text-xs font-bold uppercase tracking-wide mb-4">{pass.duration}</p>
                                            <div className="flex items-end gap-2 mb-4">
                                                <span className="text-3xl font-black text-white">KSh {pass.price}</span>
                                                <span className="text-sm font-bold text-green-500 mb-1">Save KSh {pass.savings}</span>
                                            </div>
                                            <Button className="w-full bg-zinc-800 hover:bg-amber-500 hover:text-black text-white font-black uppercase tracking-widest text-xs py-6 rounded-none transition-all">
                                                Purchase Pass
                                            </Button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </motion.div>
                    )}

                    {/* STEP 2: Choose Package */}
                    {step === 'package' && currentExperience && (
                        <motion.div
                            key="package"
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -20 }}
                            className="space-y-12"
                        >
                            <div className="text-center mb-16">
                                <button
                                    onClick={() => setStep('experience')}
                                    className="text-zinc-500 hover:text-white font-black text-xs uppercase tracking-widest mb-6 flex items-center gap-2 mx-auto"
                                >
                                    ΓåÉ Back to Experiences
                                </button>
                                <h2 className="text-4xl md:text-5xl font-black italic tracking-tighter text-white uppercase mb-4">
                                    Choose Your <span className="text-red-600">Package</span>
                                </h2>
                                <p className="text-zinc-500 text-sm font-bold uppercase tracking-widest">
                                    {currentExperience.name} - Select duration
                                </p>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl mx-auto">
                                {currentExperience.packages.map((pkg) => (
                                    <motion.button
                                        key={pkg.duration}
                                        whileHover={{ scale: 1.05, y: -8 }}
                                        whileTap={{ scale: 0.95 }}
                                        onClick={() => handlePackageSelect(pkg)}
                                        className={`relative bg-gradient-to-b from-zinc-900 to-zinc-950 border-2 p-8 text-center transition-all duration-300 ${pkg.popular ? 'border-red-600 shadow-[0_0_40px_rgba(220,38,38,0.3)]' : 'border-zinc-800 hover:border-red-600/50'
                                            }`}
                                    >
                                        {pkg.popular && (
                                            <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-red-600 px-4 py-1 text-[8px] font-black text-white uppercase tracking-widest flex items-center gap-2">
                                                <Crown className="w-3 h-3" /> Most Popular
                                            </div>
                                        )}

                                        <div className="mb-6">
                                            <div className="text-5xl font-black text-white mb-2">{pkg.duration}</div>
                                            <div className="text-xs font-black text-zinc-500 uppercase tracking-widest">Minutes</div>
                                        </div>

                                        <div className="mb-6">
                                            <div className="text-3xl font-black text-red-600 mb-2">KSh {pkg.price}</div>
                                            {pkg.savings && (
                                                <div className="text-sm font-bold text-green-500">Save KSh {pkg.savings}</div>
                                            )}
                                        </div>

                                        <div className="text-xs font-black text-zinc-400 uppercase tracking-widest mb-4">{pkg.label}</div>

                                        <div className="flex items-center justify-center gap-2 text-red-600 font-black text-xs uppercase tracking-wider">
                                            SELECT <ChevronRight className="w-4 h-4" />
                                        </div>
                                    </motion.button>
                                ))}
                            </div>

                            {/* Upsell Suggestion */}
                            <div className="max-w-2xl mx-auto bg-gradient-to-r from-amber-900/20 to-transparent border-l-4 border-amber-500 p-6">
                                <div className="flex items-start gap-4">
                                    <TrendingUp className="w-6 h-6 text-amber-500 flex-shrink-0" />
                                    <div>
                                        <h4 className="text-sm font-black text-amber-500 uppercase tracking-widest mb-2">Pro Tip</h4>
                                        <p className="text-zinc-400 text-xs font-medium">
                                            Extend to 60 minutes and save KSh 50! Longer sessions = better value.
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    )}

                    {/* STEP 3: Choose Time */}
                    {step === 'time' && selectedPackage && (
                        <motion.div
                            key="time"
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -20 }}
                            className="space-y-12"
                        >
                            <div className="text-center mb-16">
                                <button
                                    onClick={() => setStep('package')}
                                    className="text-zinc-500 hover:text-white font-black text-xs uppercase tracking-widest mb-6 flex items-center gap-2 mx-auto"
                                >
                                    ΓåÉ Back to Packages
                                </button>
                                <h2 className="text-4xl md:text-5xl font-black italic tracking-tighter text-white uppercase mb-4">
                                    Choose Your <span className="text-red-600">Time</span>
                                </h2>
                                <p className="text-zinc-500 text-sm font-bold uppercase tracking-widest">
                                    {selectedPackage.duration} minutes session
                                </p>
                            </div>

                            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4 max-w-6xl mx-auto">
                                {timeSlots.map((time) => (
                                    <button
                                        key={time}
                                        onClick={() => handleTimeSelect(time)}
                                        className={`py-6 border-2 font-black text-sm uppercase tracking-widest transition-all ${selectedTime === time
                                            ? 'bg-red-600 border-red-600 text-white'
                                            : 'bg-zinc-900 border-zinc-800 text-zinc-400 hover:border-red-600/50 hover:text-white'
                                            }`}
                                    >
                                        {time}
                                    </button>
                                ))}
                            </div>
                        </motion.div>
                    )}

                    {/* STEP 4: Choose Station */}
                    {step === 'station' && selectedTime && (
                        <motion.div
                            key="station"
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -20 }}
                            className="space-y-12"
                        >
                            <div className="text-center mb-16">
                                <button
                                    onClick={() => setStep('time')}
                                    className="text-zinc-500 hover:text-white font-black text-xs uppercase tracking-widest mb-6 flex items-center gap-2 mx-auto"
                                >
                                    ΓåÉ Back to Time Selection
                                </button>
                                <h2 className="text-4xl md:text-5xl font-black italic tracking-tighter text-white uppercase mb-4">
                                    Choose Your <span className="text-red-600">Station</span>
                                </h2>
                                <p className="text-zinc-500 text-sm font-bold uppercase tracking-widest">
                                    Available stations for {selectedTime}
                                </p>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 max-w-6xl mx-auto">
                                {availableStations.map((station) => (
                                    <button
                                        key={station.id}
                                        onClick={() => handleStationSelect(station.id)}
                                        className={`p-6 border-2 text-left transition-all ${selectedStation === station.id
                                            ? 'bg-red-600/10 border-red-600'
                                            : 'bg-zinc-900 border-zinc-800 hover:border-red-600/50'
                                            }`}
                                    >
                                        <div className="flex items-center justify-between mb-4">
                                            <h3 className="text-lg font-black uppercase tracking-tight text-white">{station.name}</h3>
                                            {selectedStation === station.id && (
                                                <CheckCircle2 className="w-6 h-6 text-red-600" />
                                            )}
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
                                            <span className="text-xs font-black text-green-500 uppercase tracking-widest">Available Now</span>
                                        </div>
                                    </button>
                                ))}
                            </div>

                            {selectedStation && (
                                <div className="max-w-2xl mx-auto">
                                    <div className="bg-zinc-900 border-2 border-red-600 p-8 mb-6">
                                        <h3 className="text-xl font-black uppercase tracking-tight text-white mb-6 flex items-center gap-3">
                                            <Info className="w-5 h-5 text-red-600" /> Booking Summary
                                        </h3>
                                        <div className="space-y-4">
                                            <div className="flex justify-between">
                                                <span className="text-zinc-500 font-bold uppercase text-sm">Experience</span>
                                                <span className="text-white font-black uppercase text-sm">{currentExperience?.name}</span>
                                            </div>
                                            <div className="flex justify-between">
                                                <span className="text-zinc-500 font-bold uppercase text-sm">Duration</span>
                                                <span className="text-white font-black uppercase text-sm">{selectedPackage.duration} min</span>
                                            </div>
                                            <div className="flex justify-between">
                                                <span className="text-zinc-500 font-bold uppercase text-sm">Time</span>
                                                <span className="text-white font-black uppercase text-sm">{selectedTime}</span>
                                            </div>
                                            <div className="flex justify-between">
                                                <span className="text-zinc-500 font-bold uppercase text-sm">Station</span>
                                                <span className="text-white font-black uppercase text-sm">{stations.find(s => s.id === selectedStation)?.name}</span>
                                            </div>
                                            <div className="pt-4 border-t border-zinc-800 flex justify-between items-end">
                                                <span className="text-zinc-500 font-bold uppercase text-sm">Total</span>
                                                <span className="text-3xl font-black text-red-600">KSh {selectedPackage.price}</span>
                                            </div>
                                        </div>
                                    </div>

                                    <Button
                                        onClick={handleBooking}
                                        className="w-full bg-red-600 hover:bg-red-700 text-white text-xl font-black uppercase tracking-widest py-8 rounded-none shadow-[0_0_40px_rgba(220,38,38,0.3)]"
                                    >
                                        <span className="flex items-center gap-3">
                                            Pay & Confirm <ChevronRight className="w-6 h-6" />
                                        </span>
                                    </Button>
                                </div>
                            )}
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* M-Pesa Payment Modal */}
            <MpesaPaymentModal
                isOpen={isPaymentModalOpen}
                onClose={() => setIsPaymentModalOpen(false)}
                amount={selectedPackage?.price || 0}
                orderId={`SESSION-${Math.random().toString(36).substr(2, 9).toUpperCase()}`}
                customerName="Gamer"
                customerPhone=""
                onPaymentComplete={handlePaymentComplete}
            />
        </div>
    );
}

import { useState, useMemo } from 'react';
import { Filter, X } from 'lucide-react';
import ProductCard from '../components/ProductCard';
import ProductModal from '../components/ProductModal';
import QuickViewModal from '../components/QuickViewModal';
import ShopHeader from '../components/ShopHeader';
import FilterSidebar, { FilterOptions } from '../components/FilterSidebar';
import QuickFilterPills from '../components/QuickFilterPills';
import MerchandisingSection from '../components/MerchandisingSection';
import { useProducts } from '../hooks/useProducts';
import { useCart } from '../contexts/CartContext';
import GamifiedSection from '../components/GamifiedSection';
import { Product } from '../types/product';
import { Button } from '../components/ui/button';

interface ShopProps {
    searchQuery: string;
}

export default function Shop({ searchQuery }: ShopProps) {
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
    const [quickViewProduct, setQuickViewProduct] = useState<Product | null>(null);
    const [isProductModalOpen, setIsProductModalOpen] = useState(false);
    const [isQuickViewOpen, setIsQuickViewOpen] = useState(false);
    const [isMobileFilterOpen, setIsMobileFilterOpen] = useState(false);
    const [comparedProducts, setComparedProducts] = useState<Product[]>([]);

    const [filters, setFilters] = useState<FilterOptions>({
        categories: [],
        platforms: [],
        priceRange: [0, 999999],
        availability: [],
        deals: [],
        brands: [],
    });

    const { products, loading } = useProducts();
    const { addToCart } = useCart();

    // Apply all filters
    const filteredProducts = useMemo(() => {
        return products.filter((product) => {
            // Search query
            const matchesSearch =
                searchQuery === '' ||
                product.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                product.description.toLowerCase().includes(searchQuery.toLowerCase());

            // Category filter
            const matchesCategory =
                filters.categories.length === 0 ||
                filters.categories.includes(product.category);

            // Platform filter
            const matchesPlatform =
                filters.platforms.length === 0 ||
                (product.platform && product.platform.some(p => filters.platforms.includes(p)));

            // Price range filter
            const matchesPrice =
                product.price >= filters.priceRange[0] &&
                product.price <= filters.priceRange[1];

            // Availability filter
            const matchesAvailability =
                filters.availability.length === 0 ||
                (filters.availability.includes('In Stock') && product.inStock) ||
                (filters.availability.includes('Pre-order') && product.isPreOrder);

            // Deals filter
            const matchesDeals =
                filters.deals.length === 0 ||
                (filters.deals.includes('Sale') && product.originalPrice && product.originalPrice > product.price) ||
                (filters.deals.includes('Bundle') && product.tags?.includes('BUNDLE')) ||
                (filters.deals.includes('Best Value') && product.rating >= 4.7);

            // Brand filter
            const matchesBrand =
                filters.brands.length === 0 ||
                (product.brand && filters.brands.includes(product.brand));

            return matchesSearch && matchesCategory && matchesPlatform && matchesPrice &&
                matchesAvailability && matchesDeals && matchesBrand;
        });
    }, [products, searchQuery, filters]);

    // Merchandising sections
    const bundleProducts = useMemo(() =>
        products.filter(p => p.tags?.includes('BUNDLE')).slice(0, 5),
        [products]
    );

    const saleProducts = useMemo(() =>
        products.filter(p => p.originalPrice && p.originalPrice > p.price).slice(0, 5),
        [products]
    );

    const topRatedProducts = useMemo(() =>
        products.filter(p => p.rating >= 4.7).slice(0, 5),
        [products]
    );

    const underBudgetProducts = useMemo(() =>
        products.filter(p => p.price < 5000).slice(0, 5),
        [products]
    );

    // View product details
    const handleViewDetails = (product: Product) => {
        setSelectedProduct(product);
        setIsProductModalOpen(true);
    };

    // Quick view
    const handleQuickView = (product: Product) => {
        setQuickViewProduct(product);
        setIsQuickViewOpen(true);
    };

    // Compare
    const handleCompare = (product: Product) => {
        if (comparedProducts.find(p => p.id === product.id)) {
            setComparedProducts(comparedProducts.filter(p => p.id !== product.id));
        } else if (comparedProducts.length < 4) {
            setComparedProducts([...comparedProducts, product]);
        }
    };

    // Quick filter selection
    const handleQuickFilterSelect = (filter: any) => {
        if (filter.type === 'price') {
            setFilters({ ...filters, priceRange: filter.value });
        } else if (filter.type === 'category') {
            setFilters({ ...filters, categories: [filter.value] });
        } else if (filter.type === 'platform') {
            setFilters({ ...filters, platforms: [filter.value] });
        } else if (filter.type === 'deal') {
            setFilters({ ...filters, deals: [filter.value] });
        }
    };

    const activeFilterCount =
        filters.categories.length +
        filters.platforms.length +
        filters.availability.length +
        filters.deals.length +
        filters.brands.length +
        (filters.priceRange[0] !== 0 || filters.priceRange[1] !== 999999 ? 1 : 0);

    return (
        <div className="min-h-screen bg-black text-white">
            {/* Shop Header */}
            <ShopHeader />

            {/* Main Content */}
            <div className="w-full sm:container mx-auto px-0 sm:px-4">
                <div className="flex gap-6">
                    {/* Desktop Filter Sidebar */}
                    <div className="hidden lg:block w-64 flex-shrink-0">
                        <FilterSidebar
                            filters={filters}
                            onFilterChange={setFilters}
                        />
                    </div>

                    {/* Main Products Area */}
                    <div className="flex-1 py-8 px-4 sm:px-0">
                        {/* Mobile Filter Button */}
                        <div className="lg:hidden mb-6">
                            <Button
                                onClick={() => setIsMobileFilterOpen(true)}
                                className="w-full bg-zinc-900 border border-zinc-800 hover:border-red-600 text-white font-black uppercase tracking-wider rounded-none py-4 flex items-center justify-center gap-2"
                            >
                                <Filter className="h-4 w-4" />
                                Filters
                                {activeFilterCount > 0 && (
                                    <span className="bg-red-600 text-white text-xs font-black px-2 py-0.5 rounded-full ml-2">
                                        {activeFilterCount}
                                    </span>
                                )}
                            </Button>
                        </div>

                        {/* Quick Filter Pills */}
                        <QuickFilterPills onFilterSelect={handleQuickFilterSelect} />

                        {/* Featured Bundles */}
                        {bundleProducts.length > 0 && (
                            <MerchandisingSection
                                title="Featured Bundles"
                                subtitle="Best value packs for complete setups"
                                products={bundleProducts}
                                icon="bundle"
                                onAddToCart={addToCart}
                                onViewDetails={handleViewDetails}
                                onQuickView={handleQuickView}
                                onCompare={handleCompare}
                            />
                        )}

                        {/* Hot Deals */}
                        {saleProducts.length > 0 && (
                            <MerchandisingSection
                                title="Hot Deals"
                                subtitle="Limited time offers"
                                products={saleProducts}
                                icon="deals"
                                onAddToCart={addToCart}
                                onViewDetails={handleViewDetails}
                                onQuickView={handleQuickView}
                                onCompare={handleCompare}
                            />
                        )}

                        {/* Under KSh 5,000 */}
                        {underBudgetProducts.length > 0 && (
                            <MerchandisingSection
                                title="Under KSh 5,000"
                                subtitle="Budget-friendly gaming gear"
                                products={underBudgetProducts}
                                icon="deals"
                                onAddToCart={addToCart}
                                onViewDetails={handleViewDetails}
                                onQuickView={handleQuickView}
                                onCompare={handleCompare}
                            />
                        )}

                        {/* All Products */}
                        <GamifiedSection className="mb-8">
                            {loading ? (
                                <div className="flex justify-center py-12">
                                    <div className="text-lg text-gray-400 animate-pulse">Loading products...</div>
                                </div>
                            ) : (
                                <>
                                    <div className="mb-6">
                                        <h2 className="text-2xl font-bold text-white">
                                            {filteredProducts.length > 0
                                                ? `All Products (${filteredProducts.length})`
                                                : 'No products found'}
                                        </h2>
                                        {activeFilterCount > 0 && (
                                            <p className="mt-1 text-sm text-gray-400">
                                                {activeFilterCount} filter{activeFilterCount > 1 ? 's' : ''} applied
                                            </p>
                                        )}
                                    </div>
                                    <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5">
                                        {filteredProducts.map((product) => (
                                            <ProductCard
                                                key={product.id}
                                                product={product}
                                                onAddToCart={addToCart}
                                                onViewDetails={handleViewDetails}
                                                onQuickView={handleQuickView}
                                                onCompare={handleCompare}
                                            />
                                        ))}
                                    </div>
                                </>
                            )}
                        </GamifiedSection>

                        {/* Top Rated */}
                        {topRatedProducts.length > 0 && (
                            <MerchandisingSection
                                title="Top Rated"
                                subtitle="Highest rated by gamers"
                                products={topRatedProducts}
                                icon="trending"
                                onAddToCart={addToCart}
                                onViewDetails={handleViewDetails}
                                onQuickView={handleQuickView}
                                onCompare={handleCompare}
                            />
                        )}
                    </div>
                </div>
            </div>

            {/* Mobile Filter Modal */}
            {isMobileFilterOpen && (
                <div className="lg:hidden">
                    <FilterSidebar
                        filters={filters}
                        onFilterChange={setFilters}
                        onClose={() => setIsMobileFilterOpen(false)}
                        isMobile={true}
                    />
                </div>
            )}

            {/* Product Detail Modal */}
            <ProductModal
                product={selectedProduct}
                isOpen={isProductModalOpen}
                onClose={() => setIsProductModalOpen(false)}
                onAddToCart={addToCart}
            />

            {/* Quick View Modal */}
            <QuickViewModal
                product={quickViewProduct}
                isOpen={isQuickViewOpen}
                onClose={() => setIsQuickViewOpen(false)}
                onAddToCart={addToCart}
                onViewFullDetails={handleViewDetails}
            />

            {/* Comparison Bar (if products selected) */}
            {comparedProducts.length > 0 && (
                <div className="fixed bottom-0 left-0 right-0 bg-zinc-950 border-t-2 border-red-600 p-4 z-40">
                    <div className="container mx-auto flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <span className="text-sm font-black uppercase tracking-wider text-white">
                                Comparing {comparedProducts.length} product{comparedProducts.length > 1 ? 's' : ''}
                            </span>
                            <div className="flex gap-2">
                                {comparedProducts.map(product => (
                                    <div key={product.id} className="relative">
                                        <img src={product.image} alt={product.name} className="h-12 w-12 object-cover border border-zinc-800" />
                                        <button
                                            onClick={() => handleCompare(product)}
                                            className="absolute -top-1 -right-1 bg-red-600 text-white rounded-full p-0.5"
                                        >
                                            <X className="h-3 w-3" />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        </div>
                        <div className="flex gap-3">
                            <Button
                                onClick={() => setComparedProducts([])}
                                className="bg-transparent border border-zinc-800 hover:border-red-600 text-white font-black uppercase tracking-wider rounded-none text-xs px-4 py-2"
                            >
                                Clear All
                            </Button>
                            <Button
                                className="bg-red-600 hover:bg-red-700 text-white font-black uppercase tracking-wider rounded-none text-xs px-6 py-2"
                            >
                                Compare Now
                            </Button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { Trash2, ShoppingCart, Heart, ChevronUp } from 'lucide-react';
import { useWishlist } from '../contexts/WishlistContext';
import { useCart } from '../contexts/CartContext';
import ProductCard from '../components/ProductCard';
import { Button } from '../components/ui/button';
import { useState, useEffect, useRef } from 'react';
import ProductModal from '../components/ProductModal';
import QuickViewModal from '../components/QuickViewModal';
import { Product } from '../types/product';
import redGridBg from '../assets/images/red-grid-bg.png';

export default function Wishlist() {
    const { wishlist, clearWishlist, removeFromWishlist } = useWishlist();
    const { addToCart } = useCart();
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
    const [quickViewProduct, setQuickViewProduct] = useState<Product | null>(null);
    const [isProductModalOpen, setIsProductModalOpen] = useState(false);
    const [isQuickViewOpen, setIsQuickViewOpen] = useState(false);
    const [showScrollTop, setShowScrollTop] = useState(false);
    const [scrollProgress, setScrollProgress] = useState(0);
    const productsGridRef = useRef<HTMLDivElement>(null);

    // Scroll to top when page loads
    useEffect(() => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }, []);

    // Track scroll position for scroll-to-top button and progress bar
    useEffect(() => {
        const handleScroll = () => {
            const scrollTop = window.pageYOffset || document.documentElement.scrollTop;
            const scrollHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
            const progress = (scrollTop / scrollHeight) * 100;

            setScrollProgress(progress);
            setShowScrollTop(scrollTop > 400);
        };

        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const scrollToTop = () => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const scrollToProducts = () => {
        productsGridRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    };

    const handleViewDetails = (product: Product) => {
        setSelectedProduct(product);
        setIsProductModalOpen(true);
    };

    const handleQuickView = (product: Product) => {
        setQuickViewProduct(product);
        setIsQuickViewOpen(true);
    };

    const handleAddAllToCart = () => {
        wishlist.forEach(product => {
            if (product.inStock) {
                addToCart(product);
            }
        });
    };

    return (
        <div className="min-h-screen bg-black text-white">
            {/* Scroll Progress Bar */}
            <div className="fixed top-0 left-0 right-0 h-1 bg-zinc-900 z-50">
                <div
                    className="h-full bg-gradient-to-r from-red-600 to-red-500 transition-all duration-300 shadow-[0_0_10px_rgba(220,38,38,0.8)]"
                    style={{ width: `${scrollProgress}%` }}
                />
            </div>

            {/* Header */}
            <div className="relative py-16 sm:py-20 overflow-hidden border-b border-zinc-800">
                {/* 3D Grid Background */}
                <div className="absolute inset-0 z-0">
                    <img
                        src={redGridBg}
                        alt=""
                        className="w-full h-full object-cover opacity-30 mix-blend-screen"
                    />
                    <div className="absolute inset-0 bg-gradient-to-b from-black via-transparent to-black z-10" />
                </div>

                <div className="w-full sm:container relative z-20 mx-auto px-4 sm:px-4">
                    <div className="flex items-center gap-4 mb-4">
                        <Heart className="h-8 w-8 sm:h-10 sm:w-10 text-red-600 fill-red-600 animate-pulse" />
                        <h1 className="text-4xl sm:text-6xl font-black italic tracking-tighter text-white">
                            MY <span className="text-red-600">WISHLIST</span>
                        </h1>
                    </div>
                    <div className="flex items-center justify-between flex-wrap gap-4">
                        <p className="text-base sm:text-xl text-gray-300 font-bold">
                            {wishlist.length} {wishlist.length === 1 ? 'item' : 'items'} saved for later
                        </p>
                        {wishlist.length > 0 && (
                            <Button
                                onClick={scrollToProducts}
                                className="bg-red-600/20 border border-red-600 hover:bg-red-600 text-white font-black uppercase tracking-wider rounded-none py-3 px-6 text-xs transition-all"
                            >
                                <ChevronUp className="h-4 w-4 mr-2 rotate-180" />
                                View Items
                            </Button>
                        )}
                    </div>
                </div>
            </div>

            {/* Content */}
            <div className="w-full sm:container mx-auto px-4 sm:px-4 py-8">
                {wishlist.length === 0 ? (
                    /* Empty State */
                    <div className="flex flex-col items-center justify-center py-20 text-center">
                        <div className="relative mb-6">
                            <Heart className="h-24 w-24 text-zinc-800" />
                            <div className="absolute inset-0 bg-red-600/10 blur-3xl" />
                        </div>
                        <h2 className="text-2xl sm:text-3xl font-black italic uppercase tracking-tighter text-white mb-3">
                            Your Wishlist is Empty
                        </h2>
                        <p className="text-zinc-400 font-bold mb-8 max-w-md">
                            Save your favorite products for later by clicking the heart icon on any product.
                        </p>
                        <Button
                            onClick={() => window.location.href = '/shop'}
                            className="bg-red-600 hover:bg-red-700 text-white font-black uppercase tracking-wider rounded-none py-6 px-8 text-sm shadow-[0_0_20px_rgba(220,38,38,0.3)]"
                        >
                            Continue Shopping
                        </Button>
                    </div>
                ) : (
                    <>
                        {/* Action Buttons */}
                        <div className="flex flex-wrap gap-3 mb-8">
                            <Button
                                onClick={handleAddAllToCart}
                                className="bg-red-600 hover:bg-red-700 text-white font-black uppercase tracking-wider rounded-none py-4 px-6 text-sm flex items-center gap-2 shadow-[0_0_20px_rgba(220,38,38,0.3)]"
                            >
                                <ShoppingCart className="h-4 w-4" />
                                Add All to Cart ({wishlist.filter(p => p.inStock).length})
                            </Button>
                            <Button
                                onClick={clearWishlist}
                                className="bg-transparent border-2 border-zinc-800 hover:border-red-600 hover:bg-red-600/10 text-white font-black uppercase tracking-wider rounded-none py-4 px-6 text-sm flex items-center gap-2 transition-all"
                            >
                                <Trash2 className="h-4 w-4" />
                                Clear All
                            </Button>
                        </div>

                        {/* Horizontal Scrollable Products Carousel */}
                        <div ref={productsGridRef} className="scroll-mt-20 relative group/carousel">
                            {/* Section Header */}
                            <div className="flex items-center justify-between mb-6">
                                <h2 className="text-xl sm:text-2xl font-black italic uppercase tracking-tighter text-white">
                                    Your <span className="text-red-600">Favorites</span>
                                </h2>
                                <div className="flex items-center gap-2">
                                    <button
                                        onClick={() => {
                                            const container = document.getElementById('wishlist-scroll-container');
                                            if (container) container.scrollBy({ left: -400, behavior: 'smooth' });
                                        }}
                                        className="p-2 bg-zinc-900 hover:bg-red-600 text-zinc-400 hover:text-white border border-zinc-800 hover:border-red-600 transition-all"
                                        aria-label="Scroll left"
                                    >
                                        <ChevronUp className="h-5 w-5 -rotate-90" />
                                    </button>
                                    <button
                                        onClick={() => {
                                            const container = document.getElementById('wishlist-scroll-container');
                                            if (container) container.scrollBy({ left: 400, behavior: 'smooth' });
                                        }}
                                        className="p-2 bg-zinc-900 hover:bg-red-600 text-zinc-400 hover:text-white border border-zinc-800 hover:border-red-600 transition-all"
                                        aria-label="Scroll right"
                                    >
                                        <ChevronUp className="h-5 w-5 rotate-90" />
                                    </button>
                                </div>
                            </div>

                            {/* Horizontal Scroll Container */}
                            <div
                                id="wishlist-scroll-container"
                                className="flex gap-4 overflow-x-auto pb-4 snap-x snap-mandatory scroll-smooth"
                                style={{
                                    scrollbarWidth: 'thin',
                                    scrollbarColor: '#dc2626 #18181b'
                                }}
                            >
                                {wishlist.map((product) => (
                                    <div
                                        key={product.id}
                                        className="flex-shrink-0 w-[280px] sm:w-[320px] snap-start"
                                    >
                                        <ProductCard
                                            product={product}
                                            onAddToCart={addToCart}
                                            onViewDetails={handleViewDetails}
                                            onQuickView={handleQuickView}
                                            onCompare={(product) => {
                                                console.log('Compare:', product);
                                            }}
                                        />
                                    </div>
                                ))}
                            </div>

                            {/* Custom Scrollbar Styling */}
                            <style>{`
                                #wishlist-scroll-container::-webkit-scrollbar {
                                    height: 8px;
                                }
                                #wishlist-scroll-container::-webkit-scrollbar-track {
                                    background: #18181b;
                                    border-radius: 0;
                                }
                                #wishlist-scroll-container::-webkit-scrollbar-thumb {
                                    background: linear-gradient(to right, #dc2626, #ef4444);
                                    border-radius: 0;
                                    box-shadow: 0 0 10px rgba(220, 38, 38, 0.5);
                                }
                                #wishlist-scroll-container::-webkit-scrollbar-thumb:hover {
                                    background: linear-gradient(to right, #b91c1c, #dc2626);
                                }
                            `}</style>
                        </div>

                        {/* Traditional Grid View (Optional - can be toggled) */}
                        <div className="mt-12">
                            <h3 className="text-lg font-black italic uppercase tracking-tighter text-white mb-4">
                                All <span className="text-red-600">Products</span>
                            </h3>
                            <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5">
                                {wishlist.map((product) => (
                                    <ProductCard
                                        key={product.id}
                                        product={product}
                                        onAddToCart={addToCart}
                                        onViewDetails={handleViewDetails}
                                        onQuickView={handleQuickView}
                                        onCompare={(product) => {
                                            console.log('Compare:', product);
                                        }}
                                    />
                                ))}
                            </div>
                        </div>

                        {/* Stats */}
                        <div className="mt-12 grid grid-cols-1 sm:grid-cols-3 gap-4">
                            <div className="bg-zinc-900/50 border border-zinc-800 p-6">
                                <p className="text-xs font-black uppercase tracking-wider text-zinc-500 mb-2">Total Items</p>
                                <p className="text-3xl font-black italic text-white">{wishlist.length}</p>
                            </div>
                            <div className="bg-zinc-900/50 border border-zinc-800 p-6">
                                <p className="text-xs font-black uppercase tracking-wider text-zinc-500 mb-2">In Stock</p>
                                <p className="text-3xl font-black italic text-green-500">
                                    {wishlist.filter(p => p.inStock).length}
                                </p>
                            </div>
                            <div className="bg-zinc-900/50 border border-zinc-800 p-6">
                                <p className="text-xs font-black uppercase tracking-wider text-zinc-500 mb-2">Total Value</p>
                                <p className="text-3xl font-black italic text-red-600">
                                    KSh {wishlist.reduce((sum, p) => sum + p.price, 0).toLocaleString()}
                                </p>
                            </div>
                        </div>
                    </>
                )}
            </div>

            {/* Product Detail Modal */}
            <ProductModal
                product={selectedProduct}
                isOpen={isProductModalOpen}
                onClose={() => setIsProductModalOpen(false)}
                onAddToCart={addToCart}
            />

            {/* Quick View Modal */}
            <QuickViewModal
                product={quickViewProduct}
                isOpen={isQuickViewOpen}
                onClose={() => setIsQuickViewOpen(false)}
                onAddToCart={addToCart}
                onViewFullDetails={handleViewDetails}
            />

            {/* Scroll to Top Button */}
            {showScrollTop && (
                <button
                    onClick={scrollToTop}
                    className="fixed bottom-8 right-8 z-40 p-4 bg-red-600 hover:bg-red-700 text-white border-2 border-red-500 shadow-[0_0_30px_rgba(220,38,38,0.6)] transition-all duration-300 hover:scale-110 group"
                    style={{ clipPath: 'polygon(0 0, 100% 0, 100% 70%, 85% 100%, 0 100%)' }}
                    aria-label="Scroll to top"
                >
                    <ChevronUp className="h-6 w-6 group-hover:animate-bounce" />
                    {/* Glow effect */}
                    <div className="absolute -inset-2 bg-red-600/20 blur-xl opacity-0 group-hover:opacity-100 transition-opacity -z-10" />
                </button>
            )}

            {/* Vertical Scroll Navigation Bar */}
            {wishlist.length > 0 && (
                <div className="fixed right-4 top-1/2 -translate-y-1/2 z-40 hidden lg:flex flex-col items-center gap-3">
                    {/* Scroll Up Button */}
                    <button
                        onClick={() => window.scrollBy({ top: -400, behavior: 'smooth' })}
                        className="p-3 bg-zinc-900 hover:bg-red-600 text-zinc-400 hover:text-white border border-zinc-800 hover:border-red-600 transition-all duration-300 group"
                        style={{ clipPath: 'polygon(0 0, 100% 0, 100% 80%, 50% 100%, 0 80%)' }}
                        aria-label="Scroll up"
                    >
                        <ChevronUp className="h-5 w-5 group-hover:animate-bounce" />
                    </button>

                    {/* Scroll Track */}
                    <div className="relative h-64 w-1 bg-zinc-900 border-l border-r border-zinc-800">
                        {/* Progress Indicator */}
                        <div
                            className="absolute left-0 right-0 bg-gradient-to-b from-red-600 to-red-500 transition-all duration-300 shadow-[0_0_10px_rgba(220,38,38,0.8)]"
                            style={{
                                top: `${scrollProgress}%`,
                                height: '20px',
                                transform: 'translateY(-50%)'
                            }}
                        />

                        {/* Item Markers */}
                        {wishlist.slice(0, 10).map((_, index) => (
                            <div
                                key={index}
                                className="absolute left-1/2 -translate-x-1/2 w-2 h-2 bg-zinc-700 border border-zinc-600 rounded-full"
                                style={{ top: `${(index / Math.min(wishlist.length - 1, 9)) * 100}%` }}
                                title={`Item ${index + 1}`}
                            />
                        ))}
                    </div>

                    {/* Item Counter */}
                    <div className="bg-zinc-900 border border-zinc-800 px-3 py-2 min-w-[60px]">
                        <div className="text-center">
                            <p className="text-xs font-black text-red-600 leading-none">{wishlist.length}</p>
                            <p className="text-[8px] font-bold text-zinc-500 uppercase tracking-wider mt-0.5">Items</p>
                        </div>
                    </div>

                    {/* Scroll Down Button */}
                    <button
                        onClick={() => window.scrollBy({ top: 400, behavior: 'smooth' })}
                        className="p-3 bg-zinc-900 hover:bg-red-600 text-zinc-400 hover:text-white border border-zinc-800 hover:border-red-600 transition-all duration-300 group"
                        style={{ clipPath: 'polygon(0 20%, 50% 0, 100% 20%, 100% 100%, 0 100%)' }}
                        aria-label="Scroll down"
                    >
                        <ChevronUp className="h-5 w-5 rotate-180 group-hover:animate-bounce" />
                    </button>
                </div>
            )}
        </div>
    );
}
